{
  "worker_id": 2,
  "phase": "01e",
  "items": [
    {
      "source_file": "outputs/01b_PARTIAL_W1B2_1770279048.json",
      "status": "success",
      "trust_model": {
        "actors": [
          {
            "id": "actor-beacon-node",
            "name": "Beacon Node (Local)",
            "description": "The local consensus-layer client executing state transitions, validating gossip messages, serving RPC requests, and managing fork upgrades. It is the primary trusted computing base for all subgraphs in the Fulu fork and P2P interface specifications."
          },
          {
            "id": "actor-peer-node",
            "name": "Peer Node (Remote)",
            "description": "Any remote beacon node connected via the P2P network. Peers gossip data column sidecars, beacon blocks, and respond to RPC requests (DataColumnSidecarsByRange, DataColumnSidecarsByRoot). Peers are untrusted by default and must have all their messages validated."
          },
          {
            "id": "actor-block-proposer",
            "name": "Block Proposer (Validator)",
            "description": "A validator that constructs and signs beacon blocks containing blob KZG commitments. The proposer's identity is verified against the expected proposer schedule derived from the beacon state shuffling. Proposers are semi-trusted: authenticated by BLS signature but may act maliciously (e.g., equivocation)."
          },
          {
            "id": "actor-execution-layer",
            "name": "Execution Layer Client (Engine API)",
            "description": "The local execution-layer client providing blob data via the engine_getBlobsV2 API. Used during distributed blob publishing (SG-010) to retrieve blobs matching KZG commitments. Fully trusted by the consensus layer; blobs from the local EL skip cryptographic verification."
          },
          {
            "id": "actor-gossip-network",
            "name": "Gossip Network (libp2p GossipSub)",
            "description": "The underlying GossipSub protocol layer that disseminates data column sidecars and beacon blocks across subnets. Messages arriving via gossip are fully untrusted and must pass multi-stage validation before acceptance and forwarding."
          },
          {
            "id": "actor-rpc-requester",
            "name": "RPC Requester (Remote Peer)",
            "description": "A remote peer issuing ReqResp protocol requests such as DataColumnSidecarsByRange or DataColumnSidecarsByRoot. Request parameters are untrusted and must be validated against servable ranges and maximum response size limits."
          },
          {
            "id": "actor-kzg-library",
            "name": "KZG Cryptographic Library",
            "description": "The trusted KZG polynomial commitment scheme implementation providing verify_cell_kzg_proof_batch. This is a foundational cryptographic trust anchor for data availability sampling. Assumed to be correctly implemented and cryptographically sound."
          },
          {
            "id": "actor-fork-scheduler",
            "name": "Fork Scheduler / Configuration Constants",
            "description": "The set of hardcoded fork epoch constants (FULU_FORK_EPOCH, ELECTRA_FORK_EPOCH, DENEB_FORK_EPOCH, etc.) and fork version constants (FULU_FORK_VERSION, etc.) embedded in all client implementations. These are trusted configuration parameters that must be identical across all nodes to maintain consensus."
          }
        ],
        "trust_boundaries": [
          {
            "id": "tb-001",
            "from_actor": "actor-gossip-network",
            "to_actor": "actor-beacon-node",
            "description": "Data column sidecars received via gossip subnets cross into the local node's validation pipeline. This is the primary untrusted-to-trusted boundary in the Fulu P2P interface. SG-006 (data_column_sidecar_gossip_validation) implements a 13-step sequential validation pipeline with REJECT, IGNORE, and ACCEPT outcomes before any message is forwarded to peers."
          },
          {
            "id": "tb-002",
            "from_actor": "actor-block-proposer",
            "to_actor": "actor-beacon-node",
            "description": "Block proposer's signed block header is verified during gossip validation (SG-006, q_check_proposer_sig and q_check_expected_proposer). The proposer claims an identity (proposer_index) that must match the expected proposer for the slot derived from the beacon state shuffling. BLS signature verification is the authentication gate."
          },
          {
            "id": "tb-003",
            "from_actor": "actor-rpc-requester",
            "to_actor": "actor-beacon-node",
            "description": "Remote peers request data column sidecars via DataColumnSidecarsByRange (SG-008) and DataColumnSidecarsByRoot (SG-009). The local node must bound responses by MAX_REQUEST_DATA_COLUMN_SIDECARS and validate that requests fall within the data_column_serve_range to prevent resource exhaustion and information leakage."
          },
          {
            "id": "tb-004",
            "from_actor": "actor-beacon-node",
            "to_actor": "actor-execution-layer",
            "description": "The beacon node calls engine_getBlobsV2 on the local execution layer during distributed blob publishing (SG-010). Critically, blobs retrieved from the local EL skip cryptographic verification (INV-001 of SG-010), creating a direct trust dependency on EL integrity. A compromised EL could inject invalid blob data."
          },
          {
            "id": "tb-005",
            "from_actor": "actor-beacon-node",
            "to_actor": "actor-gossip-network",
            "description": "The local node publishes data column sidecars to gossip subnets it is subscribed to (custody or sampling) during distributed blob publishing (SG-010). Published sidecars must be valid and the anti-equivocation cache must be updated regardless of whether publishing occurs (INV-003 of SG-010)."
          },
          {
            "id": "tb-006",
            "from_actor": "actor-peer-node",
            "to_actor": "actor-beacon-node",
            "description": "ENR eth2 field exchange during peer discovery (SG-012). Peers advertise their fork digest and next fork version/epoch via ENR records. Incorrect or malicious ENR data could cause peering with incompatible nodes or prevent connection to compatible ones. BPO forks add complexity by not changing fork_version."
          },
          {
            "id": "tb-007",
            "from_actor": "actor-fork-scheduler",
            "to_actor": "actor-beacon-node",
            "description": "Fork epoch constants control state transitions (fork SG-001 fork_trigger, fork SG-002 upgrade_to_fulu) and fork version computation (P2P SG-001 compute_fork_version). These are configuration-level trust anchors: misconfiguration or divergence between clients causes chain splits. Fork epoch constants must be strictly ordered."
          },
          {
            "id": "tb-008",
            "from_actor": "actor-kzg-library",
            "to_actor": "actor-beacon-node",
            "description": "KZG proof verification (P2P SG-003 verify_data_column_sidecar_kzg_proofs) and Merkle inclusion proof verification (P2P SG-004 verify_data_column_sidecar_inclusion_proof) are the cryptographic trust anchors for data column integrity. The node trusts verify_cell_kzg_proof_batch, hash_tree_root, and is_valid_merkle_branch to be correct."
          },
          {
            "id": "tb-009",
            "from_actor": "actor-peer-node",
            "to_actor": "actor-beacon-node",
            "description": "Deprecated blob sidecar protocols (P2P SG-011 blob_sidecars_by_range_deprecated, P2P SG-013 blob_sidecars_by_root_deprecated) during the Fulu transition period. Peers may still request blob sidecars via the old API. The local node must handle these gracefully, serving only pre-Fulu data and not penalizing peers for transition-boundary requests."
          },
          {
            "id": "tb-010",
            "from_actor": "actor-gossip-network",
            "to_actor": "actor-beacon-node",
            "description": "Subnet routing boundary (P2P SG-005 compute_subnet_for_data_column_sidecar). Data column sidecars must be received on the correct subnet (column_index % DATA_COLUMN_SIDECAR_SUBNET_COUNT == subnet_id). Misrouted sidecars are rejected early in the gossip validation pipeline (q_check_subnet in SG-006)."
          }
        ],
        "assumptions": [
          {
            "id": "asm-001",
            "text": "Fork epoch constants (FULU_FORK_EPOCH, ELECTRA_FORK_EPOCH, DENEB_FORK_EPOCH, CAPELLA_FORK_EPOCH, BELLATRIX_FORK_EPOCH, ALTAIR_FORK_EPOCH) are correctly configured and strictly ordered (INV-001 of P2P SG-001). All nodes in the network share identical constant values. Any divergence causes a chain split."
          },
          {
            "id": "asm-002",
            "text": "The KZG commitment scheme (verify_cell_kzg_proof_batch) is cryptographically sound and correctly implemented. This is the foundational guarantee of data availability in the PeerDAS / Fulu data column sampling scheme. A break in KZG security would undermine the entire data availability layer."
          },
          {
            "id": "asm-003",
            "text": "The Merkle tree implementation (hash_tree_root, is_valid_merkle_branch, get_generalized_index, get_subtree_index) is correct and collision-resistant. The KZG_COMMITMENTS_INCLUSION_PROOF_DEPTH is fixed at 4 (INV-001 of P2P SG-004). This links kzg_commitments to the BeaconBlockBody root."
          },
          {
            "id": "asm-004",
            "text": "The local execution layer client (engine_getBlobsV2) returns authentic, untampered blob data. Blobs retrieved from the local EL skip cryptographic verification (INV-001 of P2P SG-010), creating a critical trust dependency. If the EL is compromised, invalid data columns could be published to the network."
          },
          {
            "id": "asm-005",
            "text": "The proposer shuffling algorithm deterministically produces the same expected proposer for each slot across all honest nodes running the same beacon state. This underpins the proposer_index verification in gossip validation (SG-006, q_check_expected_proposer). If shuffling computation is deferred, sidecars are IGNORED rather than REJECTED (INV-005 of P2P SG-006)."
          },
          {
            "id": "asm-006",
            "text": "The anti-equivocation cache correctly deduplicates sidecars by the tuple (slot, proposer_index, sidecar.index) as specified in INV-004 of P2P SG-006. This prevents accepting conflicting data column sidecars from equivocating proposers. The cache must be updated regardless of whether publishing occurs (INV-003 of P2P SG-010)."
          },
          {
            "id": "asm-007",
            "text": "The gossip validation pipeline (P2P SG-006) is executed atomically for each sidecar. Exactly one path from q_init to q_final is taken per sidecar (INV-003). All REJECT checks must fail before a message is forwarded (INV-001). IGNORE conditions allow re-processing later via queuing (INV-002)."
          },
          {
            "id": "asm-008",
            "text": "Wall-clock time is reasonably synchronized across nodes. Slot timing checks in gossip validation (future slot IGNORE at q_check_future_slot, finalized slot IGNORE at q_check_finalized) depend on current_slot accuracy. Clock skew can cause premature rejection or delayed acceptance. ENR epoch (INV-004 of P2P SG-012) is also determined by wall-clock time, not sync state."
          },
          {
            "id": "asm-009",
            "text": "The fork upgrade function (upgrade_to_fulu, fork SG-002) is pure and deterministic. All fields from the pre-state (electra.BeaconState) are preserved in the post-state except fork and proposer_lookahead (INV-001). No side effects on the pre-state occur (INV-006). fork.previous_version correctly chains to pre.fork.current_version (INV-002)."
          },
          {
            "id": "asm-010",
            "text": "NUMBER_OF_COLUMNS and DATA_COLUMN_SIDECAR_SUBNET_COUNT (128) are network-wide constants agreed upon by all nodes. The subnet computation (column_index % DATA_COLUMN_SIDECAR_SUBNET_COUNT) produces results in [0, 128) (INV-002 of P2P SG-005). Disagreement on these values would fragment the gossip network."
          },
          {
            "id": "asm-011",
            "text": "MAX_REQUEST_DATA_COLUMN_SIDECARS provides an effective upper bound on RPC response sizes for both DataColumnSidecarsByRange (INV-002 of P2P SG-008) and DataColumnSidecarsByRoot (INV-001 of P2P SG-009). This is the primary defense against resource exhaustion via RPC requests."
          },
          {
            "id": "asm-012",
            "text": "The finalized checkpoint is a reliable and agreed-upon anchor. finalized_checkpoint.epoch used in gossip validation (q_check_finalized in SG-006) and in RPC range computation (data_column_serve_range in SG-008, SG-009) reflects supermajority agreement. The finalized checkpoint must also be an ancestor of any accepted block (q_check_finalized_ancestor in SG-006)."
          },
          {
            "id": "asm-013",
            "text": "During the Fulu transition period, the deprecated BlobSidecarsByRange (P2P SG-011) and BlobSidecarsByRoot (P2P SG-013) endpoints serve only pre-Fulu epoch data within the range [max(current_epoch - MIN_EPOCHS, FULU_FORK_EPOCH), FULU_FORK_EPOCH). Peers are not penalized for requesting blob sidecars from FULU_FORK_EPOCH (INV-003 of both SG-011 and SG-013). These endpoints are fully deprecated after FULU_FORK_EPOCH + MIN_EPOCHS_FOR_BLOB_SIDECARS_REQUESTS."
          },
          {
            "id": "asm-014",
            "text": "BPO (Blob Parameter Only) forks do not change the fork version, only the fork epoch. ENR encoding (P2P SG-012) must handle this distinction correctly: for BPO forks, next_fork_version remains current_fork_version while next_fork_epoch is set to the planned epoch (INV-002 of P2P SG-012). Incorrect handling would cause peering incompatibility."
          },
          {
            "id": "asm-015",
            "text": "get_blob_parameters(epoch) returns epoch-dependent blob limits (max_blobs_per_block). This function is trusted to return correct and consistent parameters for each epoch across all nodes (INV-001 of P2P SG-007). Epoch-dependent parameters enable future parameter changes without hard forks."
          },
          {
            "id": "asm-016",
            "text": "The fork trigger (fork SG-001) only fires at epoch boundaries (slot % SLOTS_PER_EPOCH == 0) per INV-001, fires exactly once at FULU_FORK_EPOCH per INV-002, and is irreversible per INV-003. Once triggered, the state is permanently upgraded. This prevents fork oscillation attacks."
          },
          {
            "id": "asm-017",
            "text": "The proposer_lookahead field introduced in Fulu (EIP-7917) is freshly initialized via initialize_proposer_lookahead(pre) during the upgrade (INV-005 of fork SG-002). This new field is the only net-new addition to the BeaconState; all other fields are faithfully copied from the pre-state."
          },
          {
            "id": "asm-018",
            "text": "DataColumnSidecarsByRange responses are ordered by (slot, column_index) (INV-003 of P2P SG-008) and all sidecars of a block must be included if any are included (INV-004). Sidecars must be from the current fork choice chain (INV-005). Fork choice changes terminate the response stream."
          },
          {
            "id": "asm-019",
            "text": "Sidecars served via RPC should only come from blocks passing gossip validation (INV-004 of P2P SG-009) and should not be served for blocks failing the beacon-chain state transition (INV-005). This prevents serving invalid data to requesting peers."
          }
        ],
        "stride_analysis": [
          {
            "trust_boundary_id": "tb-001",
            "threat_type": "Spoofing",
            "description": "A malicious peer could forge a data column sidecar with a fabricated signed_block_header claiming to be from a legitimate block proposer. The sidecar would appear to originate from a valid proposer for the slot.",
            "mitigation": "Gossip validation (SG-006) verifies the proposer BLS signature against the expected proposer for the slot at q_check_proposer_sig. Invalid signatures result in REJECT. Subsequently, q_check_expected_proposer verifies that the proposer_index matches the expected proposer derived from the beacon state shuffling."
          },
          {
            "trust_boundary_id": "tb-001",
            "threat_type": "Tampering",
            "description": "A peer could tamper with the data column contents (cells), KZG commitments, or KZG proofs within a sidecar before forwarding it on the gossip network. This could inject invalid data into the data availability layer.",
            "mitigation": "Three-layer integrity verification: (1) verify_data_column_sidecar (P2P SG-002) checks structural validity -- index in [0, NUMBER_OF_COLUMNS), non-empty commitments, count within max_blobs_per_block, and equal-length arrays; (2) verify_data_column_sidecar_kzg_proofs (P2P SG-003) verifies cryptographic binding of cells to commitments via verify_cell_kzg_proof_batch; (3) verify_data_column_sidecar_inclusion_proof (P2P SG-004) verifies Merkle inclusion of kzg_commitments in the block body_root at depth 4."
          },
          {
            "trust_boundary_id": "tb-001",
            "threat_type": "Repudiation",
            "description": "A block proposer could publish conflicting data column sidecars (equivocation) for the same slot, providing different data columns to different subnets, and then deny having produced one of the conflicting versions.",
            "mitigation": "The anti-equivocation cache tracks sidecars by the tuple (slot, proposer_index, sidecar.index). Only the first valid sidecar for each tuple is accepted; duplicates are IGNORED (INV-004 of SG-006). The signed block header provides cryptographic non-repudiation evidence binding the proposer to the content."
          },
          {
            "trust_boundary_id": "tb-001",
            "threat_type": "Information Disclosure",
            "description": "Gossip validation timing and rejection/ignore behavior could leak information about the local node's state (e.g., which blocks have been finalized, which parent blocks have been seen, current slot estimate).",
            "mitigation": "The protocol uses IGNORE (rather than REJECT) for conditions that depend on local state: parent not seen (q_ignore_no_parent), future slot (q_ignore_future), pre-finalized slot (q_ignore_old), and duplicate sidecar (q_ignore_duplicate). This prevents peers from definitively inferring local node state from rejection messages. However, timing side-channels from the validation pipeline ordering may still exist."
          },
          {
            "trust_boundary_id": "tb-001",
            "threat_type": "Denial of Service",
            "description": "An attacker could flood the gossip network with invalid data column sidecars, forcing all receiving nodes to execute the expensive 13-step validation pipeline (including BLS signature verification and KZG proof verification) before rejecting them.",
            "mitigation": "Validation checks are ordered from cheapest to most expensive in SG-006: structural checks first (verify_data_column_sidecar), then subnet validation (cheap modulo operation), then slot timing checks, then proposer signature verification, then parent and fork choice checks, and finally KZG/Merkle proofs last. Early rejection at cheap steps avoids expensive cryptographic operations for most invalid messages."
          },
          {
            "trust_boundary_id": "tb-001",
            "threat_type": "Elevation of Privilege",
            "description": "A non-proposer node could attempt to inject a sidecar claiming to be from a legitimate proposer, effectively acting as a block proposer without being scheduled for the slot.",
            "mitigation": "The gossip validation pipeline verifies proposer_index against the expected proposer for the slot at q_check_expected_proposer, the final check before acceptance. If the shuffling computation is not yet available, the sidecar is IGNORED (not accepted), preventing privilege escalation. The BLS signature check at q_check_proposer_sig provides the cryptographic authentication layer."
          },
          {
            "trust_boundary_id": "tb-002",
            "threat_type": "Spoofing",
            "description": "An attacker could craft a valid-looking block header with a forged proposer_index, attempting to impersonate a scheduled proposer by guessing or reusing a BLS signature.",
            "mitigation": "BLS signature verification of the signed_block_header cryptographically binds the proposer_index to the proposer's private key. Forging a BLS signature is computationally infeasible. The signature is checked (q_check_proposer_sig) before the proposer schedule check, ensuring identity authentication precedes authorization."
          },
          {
            "trust_boundary_id": "tb-002",
            "threat_type": "Tampering",
            "description": "A legitimate proposer could maliciously construct a block with more blob KZG commitments than allowed by max_blobs_per_block for the current epoch, or with mismatched array lengths in the sidecar (column vs. commitments vs. proofs).",
            "mitigation": "P2P SG-007 (beacon_block_kzg_validation) enforces len(blob_kzg_commitments) <= get_blob_parameters(epoch).max_blobs_per_block. P2P SG-002 (verify_data_column_sidecar) enforces that column, kzg_commitments, and kzg_proofs all have equal length (INV-004). Blocks with zero commitments are explicitly allowed (INV-002 of P2P SG-007)."
          },
          {
            "trust_boundary_id": "tb-003",
            "threat_type": "Denial of Service",
            "description": "A malicious peer could issue DataColumnSidecarsByRange (SG-008) or DataColumnSidecarsByRoot (SG-009) requests with very large count values or many column identifiers, causing the responding node to perform excessive disk I/O, computation, and network transmission.",
            "mitigation": "Both RPC endpoints enforce MAX_REQUEST_DATA_COLUMN_SIDECARS as an upper bound. DataColumnSidecarsByRoot (SG-009) computes requested_columns_count = sum(len(r.columns) for r in request) and rejects if it exceeds the maximum. DataColumnSidecarsByRange (SG-008) bounds by count * NUMBER_OF_COLUMNS. The serve range is also bounded to recent epochs."
          },
          {
            "trust_boundary_id": "tb-003",
            "threat_type": "Tampering",
            "description": "A malicious RPC requester could craft requests targeting blocks outside the servable range, attempting to force the node to access historical data that may not be available, trigger error paths, or scan its full block storage.",
            "mitigation": "Both endpoints compute a data_column_serve_range = [max(current_epoch - MIN_EPOCHS_FOR_DATA_COLUMN_SIDECARS_REQUESTS, FULU_FORK_EPOCH), current_epoch]. Requests outside this range receive ResourceUnavailable(3) responses (SG-008) or are skipped (SG-009). For DataColumnSidecarsByRoot, blocks must also pass gossip validation before sidecars are served (INV-004 of SG-009)."
          },
          {
            "trust_boundary_id": "tb-003",
            "threat_type": "Information Disclosure",
            "description": "An attacker could probe which blocks the local node has stored by requesting specific block roots via DataColumnSidecarsByRoot (SG-009), systematically mapping the node's chain view and data availability.",
            "mitigation": "The specification allows skipping identifiers where the block fails gossip validation or the epoch is too old. However, response patterns (presence vs. absence of sidecars, response timing) do leak information about the node's block inventory. This is inherent to the ReqResp protocol design and partially mitigated by the serve range restriction."
          },
          {
            "trust_boundary_id": "tb-004",
            "threat_type": "Tampering",
            "description": "If the local execution layer is compromised or has a bug, it could return tampered or incorrect blob data via engine_getBlobsV2. Since blobs from the local EL skip verification (INV-001 of SG-010), these tampered blobs would be converted to data columns and published to the gossip network as if valid.",
            "mitigation": "This is a critical and intentional trust assumption in the protocol design. The local EL is trusted by construction. Mitigations are operational: ensure the EL client is authentic, up-to-date, and runs in a secure environment. Network-level redundancy provides a secondary defense -- other nodes will independently verify data columns received via gossip and reject invalid ones."
          },
          {
            "trust_boundary_id": "tb-004",
            "threat_type": "Denial of Service",
            "description": "If engine_getBlobsV2 fails, times out, or returns incomplete blob data (not all blobs matching the block's kzg_commitments are retrieved), the distributed blob publishing process aborts, potentially reducing data availability for the block across the network.",
            "mitigation": "SG-010 explicitly handles this case: if not all blobs are retrieved, the process aborts gracefully at q_no_blobs. Other nodes performing the same distributed publishing flow provide redundancy. The abort does not crash the node and does not affect other node operations. The anti-equivocation cache is not polluted by a failed attempt."
          },
          {
            "trust_boundary_id": "tb-005",
            "threat_type": "Repudiation",
            "description": "After publishing data column sidecars, a node could deny having published them if the published data is later found to be invalid or conflicting with other sidecars on the network.",
            "mitigation": "Published sidecars contain the original proposer's signed_block_header which provides cryptographic non-repudiation at the proposer level. At the publisher level, the anti-equivocation cache (INV-003 of SG-010) must be updated regardless of whether publishing occurs, ensuring local state consistency and preventing the node from later publishing a conflicting sidecar."
          },
          {
            "trust_boundary_id": "tb-005",
            "threat_type": "Elevation of Privilege",
            "description": "A node could attempt to publish data column sidecars on subnets it is not subscribed to (neither custody nor sampling), effectively acting as an unauthorized publisher and potentially influencing data availability beyond its designated role.",
            "mitigation": "SG-010 explicitly checks subscription status at q_check_subscribed. Publishing only occurs on subnets the node is subscribed to via custody or sampling duties. Non-subscribed subnets skip the publish step and proceed directly to cache update. The gossip layer also enforces that messages are only accepted from peers subscribed to the topic."
          },
          {
            "trust_boundary_id": "tb-006",
            "threat_type": "Spoofing",
            "description": "A malicious node could advertise a false ENR eth2 field, claiming to be on a different fork version or fork epoch than it actually runs. This could cause honest nodes to attempt peering with incompatible nodes, wasting connection slots and potentially partitioning the network.",
            "mitigation": "ENR records are signed by the node's identity key, preventing third-party modification. However, a node can legitimately misrepresent its own fork status in its ENR. Defense relies on detecting incompatible behavior post-connection through protocol-level fork digest validation in the libp2p handshake and status message exchange."
          },
          {
            "trust_boundary_id": "tb-006",
            "threat_type": "Denial of Service",
            "description": "During BPO fork transitions (SG-012), incorrect ENR eth2 encoding could cause nodes to fail peer discovery or disconnect from the network. Since BPO forks do not change fork_version but do change fork_epoch, nodes with incorrect BPO handling could end up with incompatible ENR digests.",
            "mitigation": "SG-012 explicitly handles BPO forks as a distinct code path: next_fork_version remains current_fork_version while next_fork_epoch is set to the planned epoch (INV-002). This ensures ENR compatibility during BPO transitions. The three-way branching (no fork, regular fork, BPO fork) covers all cases."
          },
          {
            "trust_boundary_id": "tb-007",
            "threat_type": "Tampering",
            "description": "If fork epoch constants are tampered with (e.g., via supply chain attack on client software or configuration file manipulation), the node would compute the wrong fork version for any given epoch (P2P SG-001), fork at the wrong time (fork SG-001), or produce an incorrect fork upgrade (fork SG-002), causing a chain split.",
            "mitigation": "Fork constants are hardcoded in client releases and verified through the Ethereum consensus specification. The compute_fork_version function (P2P SG-001) enforces strict ordering: GENESIS < ALTAIR < BELLATRIX < CAPELLA < DENEB < ELECTRA < FULU (INV-001). Multiple independent client implementations provide cross-validation. Exactly one branch is taken for any valid epoch (INV-002), and a valid Version is always returned (INV-003)."
          },
          {
            "trust_boundary_id": "tb-007",
            "threat_type": "Denial of Service",
            "description": "A misconfigured FULU_FORK_EPOCH could cause the fork trigger (fork SG-001) to never fire, fire at the wrong epoch boundary, or fire multiple times, permanently preventing or corrupting the network upgrade.",
            "mitigation": "Fork SG-001 enforces three critical invariants: INV-001 ensures fork only triggers at epoch boundaries (slot % SLOTS_PER_EPOCH == 0); INV-002 ensures it fires exactly once at FULU_FORK_EPOCH; INV-003 ensures irreversibility -- once triggered, the state is permanently upgraded and the fork cannot be rolled back."
          },
          {
            "trust_boundary_id": "tb-008",
            "threat_type": "Tampering",
            "description": "If the KZG library has a correctness bug allowing invalid proofs to pass verification (verify_cell_kzg_proof_batch returns true for invalid cell/commitment/proof tuples), tampered data column contents would be accepted as valid, completely undermining the data availability sampling scheme.",
            "mitigation": "The KZG library is a critical trust anchor with multiple layers of assurance: formal verification of KZG implementations, multiple independent implementations (c-kzg, go-kzg, etc.), extensive test vectors from the Ethereum consensus spec test suite, and the underlying cryptographic hardness assumption of the KZG polynomial commitment scheme over BLS12-381."
          },
          {
